require 'net/http'
require 'fileutils'
require 'set'
# require 'progressbar'

download_dir = "/Users/hemant/Downloads/AppIcons"
FileUtils::mkdir_p download_dir


def download_url(url, filename)
    File.open(filename, "wb") do |f|
        Net::HTTP.get(url) do |str|
          f.write str
          @counter += str.length 
          pbar.set(@counter)
        end
    end
end

content_types = Set.new
for line in icons.split(",")
    name = line.split(":")[0].strip()
    url = line.split(":")[1..-1].join(":").strip()

    if url and not url.empty?
        print "#{name} #{url}\n"

        resp = Net::HTTP.get_response(URI(url))

        content_types.add(resp.content_type)
    end
end

print content_types.to_a
